Voici un exemple de **middleware Express.js** qui implémente une **rate-limitation par IP avec un sliding window de 100 requêtes par minute** :

```javascript
const express = require('express');
const Redis = require('ioredis');
const { promisify } = require('util');

const app = express();
const redis = new Redis();

// Promisify certaines méthodes de Redis pour utiliser await/async
const getAsync = promisify(redis.get).bind(redis);
const setAsync = promisify(redis.set).bind(redis);
const delAsync = promisify(redis.del).bind(redis);

app.use(async (req, res, next) => {
  const ip = req.ip || req.connection.remoteAddress;

  // Clé Redis : "rate_limit:{ip}"
  const key = `rate_limit:${ip}`;

  try {
    const current = await getAsync(key);
    const count = parseInt(current) || 0;

    if (count >= 100) {
      return res.status(429).send('Trop de requêtes, veuillez réessayer plus tard.');
    }

    // Incrémenter le compteur
    await setAsync(key, count + 1, 'EX', 60); // Expiré après 1 minute

    next();
  } catch (err) {
    console.error('Erreur Redis:', err);
    res.status(500).send('Erreur serveur.');
  }
});

// Route d'exemple
app.get('/', (req, res) => {
  res.send('Hello World!');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Serveur démarré sur le port ${PORT}`);
});
```

### Explications :

- **Redis** est utilisé pour stocker les comptages de requêtes par IP.
- Le **sliding window** est simulé en utilisant un **key Redis** avec une **expiration de 1 minute** (`EX`, `60`).
- Chaque fois qu'une requête arrive, le compteur est incrémenté et expiré après 1 minute.
- Si le compteur dépasse 100, la requête est refusée avec un code `429 Too Many Requests`.

### Dépendances à installer :

```bash
npm install express ioredis
```

